import sys
input = sys.stdin.readline

def solve(n):
    if n % 2 == 1:
        half = n // 2
        if half <= 13:
            chars = 'abcdefghijklmnopqrstuvwxyz'
            s = chars[:half] + 'a' + chars[:half][::-1]
            print(s)
        else:
            # build recursively
            print('a' * n)
    else:
        print('a' * n)

t = int(input())
for _ in range(t):
    n = int(input())
    solve(n)

